SELECT [Sales Line].[Original Line No_], [NavisionEan-step0].[Item No_], [NavisionEan-step0].[Cross-Reference Type], [NavisionEan-step0].[Cross-Reference No_] AS EANCode, [NavisionEan-step0-UPC].[Cross-Reference No_] AS UPCCode, Item.No_ AS Item, Item.[Model Item No_] AS Article, Item.[Variable Code 01] AS Color, Item.[Variable Code 02] AS [Size], Item.[Season Code], Item.[Trademark Code], Item.[Configurator Relation], [Sales Line].[Document No_], Sum(Val([sales line_1.quantity])) AS qty, Sum(Val([sales line.quantity])) AS qty_real, Item.[Description 2], [Variable Code].Description AS ColorDescription
FROM (((((Item LEFT JOIN [NavisionEan-step0] ON Item.No_ = [NavisionEan-step0].[Item No_]) RIGHT JOIN [Sales Line] ON Item.No_ = [Sales Line].No_) LEFT JOIN [Variable Code] ON (Item.[Variable Group 01] = [Variable Code].[Variable Group]) AND (Item.[Variable Code 01] = [Variable Code].[Variable Code])) LEFT JOIN [NavisionEan-step0-UPC] ON Item.No_ = [NavisionEan-step0-UPC].[Item No_]) INNER JOIN [Sales Header] ON [Sales Line].[Document No_] = [Sales Header].No_) INNER JOIN [Sales Line] AS [Sales Line_1] ON ([Sales Line].[Document No_] = [Sales Line_1].[Document No_]) AND ([Sales Line].[Original Line No_] = [Sales Line_1].[Line No_])
WHERE ((([Sales Line].[Delete Reason])=""))
GROUP BY [Sales Line].[Original Line No_], [NavisionEan-step0].[Item No_], [NavisionEan-step0].[Cross-Reference Type], [NavisionEan-step0].[Cross-Reference No_], [NavisionEan-step0-UPC].[Cross-Reference No_], Item.No_, Item.[Model Item No_], Item.[Variable Code 01], Item.[Variable Code 02], Item.[Season Code], Item.[Trademark Code], Item.[Configurator Relation], [Sales Line].[Document No_], Item.[Description 2], [Variable Code].Description, [Sales Header].No_
HAVING (((Item.[Configurator Relation])=3) AND (([Sales Header].No_)=[forms]![principale]![filtroodvean]))
ORDER BY Item.[Model Item No_], Item.[Variable Code 01], Item.[Variable Code 02];

